import React, { useState } from 'react';

import { PROJECT_NAME } from 'config/constants';
import { HeadFC, Link, PageProps } from 'gatsby';

import Layout from 'hoc/Layout/Layout';
import Input from 'components/Input/Input';
import Seo from 'hoc/Seo/Seo';
import useForm from 'hooks/useForm';

import * as classes from './SignIn.module.scss';
import Button from 'components/Button/Button';

type SignInFields = {
	email: string;
	password: string;
};

const SignIn: React.FC<PageProps> = () => {
	const [loading, setLoading] = useState<boolean>(false);
	const [error, setError] = useState<string>();

	const { values, errors, handleChange, handleFocus, handleSubmit } = useForm<SignInFields>({
		initialValues: {
			email: '',
			password: ''
		},
		rules: {
			email: {
				required: true
			},
			password: {
				required: true
			}
		},
		onSubmit: submitHandler,
		onRefill: () => setError(undefined)
	});

	async function submitHandler() {
		setLoading(true);
	}

	return (
		<Layout className={classes.SignIn}>
			<div className={classes.Heading}>
				<h1 className={classes.Name}>{PROJECT_NAME}</h1>
				<h2 className={classes.Description}>Never let go of your gems</h2>
			</div>

			<form className={classes.Form} onSubmit={(e) => e.preventDefault()}>
				<Input
					inputClassName={classes.Input}
					name='email'
					placeholder='johndoe@example.com'
					value={values.email}
					disabled={loading}
					onChange={handleChange}
					onFocus={handleFocus}
					error={errors.email}
				/>

				<Input
					inputClassName={classes.Input}
					name='password'
					placeholder='password'
					value={values.password}
					disabled={loading}
					onChange={handleChange}
					onFocus={handleFocus}
					error={errors.password}
					secure
				/>

				{error && <p className={classes.Error}>{error}</p>}

				<Button className={classes.Button} onClick={handleSubmit} loading={loading}>
					Sign In
				</Button>
			</form>

			<div className={classes.Actions}>
				<Link to='/signup' className={classes.Text}>
					i don't have an account
				</Link>

				<small className={[classes.Text, classes.Separation].join(' ')}> | </small>

				<Link to='/recover' className={classes.Text}>
					help me recover account
				</Link>
			</div>
		</Layout>
	);
};

export default SignIn;

export const Head: HeadFC = () => <Seo>Sign In</Seo>;
